35	const PROCESSING_FEE = 5;
36	const FIRST_INSURANCE_SURCHARGE = 0.1;
37	const LOYALTY_DISCOUNT = 0.2;
38	const LOYALTY_THRESHOLD_YEARS = 2;
39	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
40	const CURSED_SURCHARGE = 0.5;
41	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
42	const HIGH_ENCHANTMENT_THRESHOLD = 5;
43	const DEDUCTIBLE_PER_DAMAGE = 100;
44	const CAP_MULTIPLIER = 2;
45	const DAMAGE_HIGH_ENCHANT_THRESHOLD = 8;
46	const DAMAGE_HIGH_ENCHANT_RATE = 0.5;
47	
48	const ITEM_BASE_PREMIUM: Record<string, number> = {
49	  sword: 100,
50	  rune: 25,
51	  moonstone: 25,
52	};
53	
54	const ITEM_INSURANCE_VALUE: Record<string, number> = {
55	  sword: 1000,
56	  rune: 250,
57	};
58	
59	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
60	const COMPONENT_BLOCK_SIZE = 3;
61	const COMPONENT_BLOCK_PREMIUM = 60;
62	
63	const groupCountsByType = (items: Item[]): Map<string, number> => {
64	  const counts = new Map<string, number>();
65	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
66	  return counts;
67	};
68	
69	const basePremiumForGroup = (type: string, count: number): number => {
70	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
71	  return count * ITEM_BASE_PREMIUM[type];
72	};
73	
74	const sumBasePremium = (counts: Map<string, number>): number => {
75	  let total = 0;
76	  for (const [type, count] of counts) total += basePremiumForGroup(type, count);
77	  return total;
78	};
79	
80	const isHighlyEnchanted = (item: Item): boolean =>
81	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
82	
83	const surchargeRateForItem = (item: Item): number =>
84	  (item.cursed ? CURSED_SURCHARGE : 0) +
85	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
86	
87	const surchargeForItem = (item: Item): number =>
88	  ITEM_BASE_PREMIUM[item.type] * surchargeRateForItem(item);
89	
90	const itemSurcharges = (items: Item[]): number =>
91	  items.reduce((total, item) => total + surchargeForItem(item), 0);
92	
93	const calculatePremium = (
94	  items: Item[],
95	  yearsWithMHPCO: number,
96	  isFollowUpContract: boolean,
97	): number => {
98	  const base = sumBasePremium(groupCountsByType(items));
99	  const surcharges = itemSurcharges(items);
100	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE;
101	  const loyaltyDiscount =
102	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT : 0;
103	  const followUpDiscount = isFollowUpContract ? base * FOLLOWUP_CONTRACT_DISCOUNT : 0;
104	  return Math.ceil(
105	    base + surcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
106	  );
107	};
108	
109	type Policy = {
110	  items: Item[];
111	  remainingCap: number;
112	};
113	
114	const insuranceSum = (items: Item[]): number =>
115	  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);
116	
117	const reimbursableAmount = (damage: Damage, item: Item): number =>
118	  (item.enchantment ?? 0) >= DAMAGE_HIGH_ENCHANT_THRESHOLD
119	    ? damage.amount * DAMAGE_HIGH_ENCHANT_RATE
120	    : damage.amount;
121	
122	const payoutForDamage = (damage: Damage, item: Item): number =>
123	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE_PER_DAMAGE);
124	
125	const claimPayout = (policy: Policy, incident: Incident): number => {
126	  const grossPayout = incident.damages.reduce((sum, d) => {
127	    const item = policy.items.find((i) => i.type === d.itemType)!;
128	    return sum + payoutForDamage(d, item);
129	  }, 0);
130	  return Math.floor(Math.min(grossPayout, policy.remainingCap));
131	};
132	
133	export const runScenario = (scenario: Scenario): ScenarioResult => {
134	  const policies: Policy[] = [];
135	  const results: StepResult[] = scenario.steps.map((step) => {
136	    if (step.op === "quote") {
137	      const isFollowUpContract = policies.length >= 1;
138	      policies.push({ items: step.items, remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER });
139	      return {
140	        premium: calculatePremium(step.items, scenario.customer.yearsWithMHPCO, isFollowUpContract),
141	      };
142	    }
143	    const policy = policies[step.policy];
144	    const payout = claimPayout(policy, step.incident);
145	    policy.remainingCap -= payout;
146	    return { payout, remainingCap: policy.remainingCap };
147	  });
148	  return { results };
149	};
